def fibonacci_recursive(n):

    if n <= 0:
        return []
    elif n == 1:
        return [0]
    else:
        fib = fibonacci_recursive(n-1)
        fib.append(fib[-1] + fib[-1])
        return fib

def fibonacci_recursive_iterative(n):

